<template>
    <div class="demo-content">
        <h1>沿着svg路径运动</h1>
        <h4>主要代码：</h4>
        <div class="field">
            <div class="field-left field-border">
                <pre>
                    <code-copy :code="svgCode" :btnClssName="'copy-btn'"></code-copy>
                    <code>{{svgCode}}</code>
                </pre>
            </div>
            <div class="field-right field-border">
                <div class="to-animate" ref="box1"></div>
                <div class="to-animate" ref="box2"></div>
                <div class="to-animate" ref="box3"></div>
                <svg style="width:100%;height:100%">
                    <g>
                        <rect ref="path1" x="50" y="50" rx="10" ry="10" width="200" height="100" style="fill:none;stroke-width:1;stroke:rgb(0,0,0)"></rect>
                        <circle ref="path2" cx="350" cy="100" r="50" style="stroke-width:1;fill:none;stroke:#000"></circle>
                        <path ref="path3" d="M50 200 l200 0 l0 100 l200 0 l0 -100 l200 0" style="stroke:#000;stroke-width:1;fill:none"></path>
                    </g>
                </svg>
            </div>
        </div>
    </div>
</template>

<script>
import { onMounted, onUpdated, ref, onBeforeUnmount, reactive } from "vue";
import { Utils } from "../../utils/utils";
export default {
    setup() {
        const box1 = ref(null);
        const box2 = ref(null);
        const box3 = ref(null);
        const path1 = ref(null);
        const path2 = ref(null);
        const path3 = ref(null);
        const len1 = ref(0);
        const len2 = ref(0);
        const len3 = ref(0);
        const start = ref(performance.now());
        let animationFrameId1 = reactive(null);
        let animationFrameId2 = reactive(null);
        let animationFrameId3 = reactive(null);
        const svgCode = ref(` //初始获取svg路径总长度
onMounted(() => {
    len1.value = path1.value.getTotalLength();
    len2.value = path2.value.getTotalLength();
    len3.value = path3.value.getTotalLength();
    frame(path1.value, len1.value, box1.value, 1);
    frame(path2.value, len2.value, box2.value, 2);
    frame(path3.value, len3.value, box3.value, 3);
});

 const frame = (path, len, box, type) => {
    var now = performance.now();
    var phase = ((now - start.value) / 6000) % 1;
    var point = path.getPointAtLength(len * phase);
    box.style.transform = "translate3d(" + point.x + "px," + point.y + "px,0)"; // IE
    box.style.WebkitTransform = "translate3d(" + point.x + "px," + point.y + "px,0)"; // Chrome&Safari
    const timer = requestAnimationFrame(() => {
        frame(path, len, box, type);
    });
    if (type === 1) {
        animationFrameId1 = timer;
    } else if (type === 2) {
        animationFrameId2 = timer;
    } else {
        animationFrameId3 = timer;
    }
};

onBeforeUnmount(() => {
    cancelAnimationFrame(animationFrameId1);
    cancelAnimationFrame(animationFrameId2);
    cancelAnimationFrame(animationFrameId3);
});
        `);

        const frame = (path, len, box, type) => {
            var now = performance.now();
            var phase = ((now - start.value) / 6000) % 1;
            var point = path.getPointAtLength(len * phase);
            box.style.transform = "translate3d(" + point.x + "px," + point.y + "px,0)"; // IE
            box.style.WebkitTransform = "translate3d(" + point.x + "px," + point.y + "px,0)"; // Chrome&Safari
            const timer = requestAnimationFrame(() => {
                frame(path, len, box, type);
            });
            if (type === 1) {
                animationFrameId1 = timer;
            } else if (type === 2) {
                animationFrameId2 = timer;
            } else {
                animationFrameId3 = timer;
            }
        };

        onMounted(() => {
            len1.value = path1.value.getTotalLength();
            len2.value = path2.value.getTotalLength();
            len3.value = path3.value.getTotalLength();
            frame(path1.value, len1.value, box1.value, 1);
            frame(path2.value, len2.value, box2.value, 2);
            frame(path3.value, len3.value, box3.value, 3);
            Utils.highlightCode();
        });

        onUpdated(() => {
            Utils.highlightCode();
        });

        onBeforeUnmount(() => {
            cancelAnimationFrame(animationFrameId1);
            cancelAnimationFrame(animationFrameId2);
            cancelAnimationFrame(animationFrameId3);
        });

        return {
            start,
            box1,
            box2,
            box3,
            path1,
            path2,
            path3,
            len1,
            len2,
            len3,
            frame,
            svgCode
        };
    }
};
</script>

<style lang="scss" scoped>
.demo-content {
    width: 100%;
    height: 100%;
    padding: 16px;
    overflow: auto;
    display: flex;
    flex-direction: column;

    .field {
        display: flex;
        width: 100%;
        height: 400px;
        margin: 16px 0;
        flex: 1;
        height: 0;

        .field-left {
            flex: 1;
            height: 100%;
            width: 0;

            pre {
                margin: 0;
                padding: 0;
                height: 100%;
                display: flex;
                width: 100%;
                position: relative;

                code {
                    width: 100%;
                }
            }
        }

        .field-right {
            margin-left: 16px;
            width: 50%;
            height: 100%;
            position: relative;

            .to-animate {
                width: 20px;
                height: 20px;
                background: green;
                position: absolute;
                top: -10px;
                left: -10px;
                border-radius: 100%;
            }
        }

        .field-border {
            border: 1px solid #ececec;
        }
    }
}
</style>
